    play: '<path d="m9 7 8 5-8 5Z"/>',
    volume: '<path d="M5 10h3l4-3v10l-4-3H5Z"/><path d="M15 9.5c1.4 1.4 1.4 3.6 0 5M17.5 7c2.8 2.8 2.8 7.2 0 10"/>',
